  1 import Foundation
  2 import os
  3 
  4 public actor CodexConnector: UsageConnector {
  5     nonisolated public let vendor: Vendor = .codex
  6 
  7     private enum IdentitySource: String {
  8         case responseBody = "response_body"
  9         case credentials = "credentials"
 10         case cache = "cache"
 11     }
 12 
 13     private let auth: CodexAuthProviding
 14     private let logger: FileLogger
 15     private let session: URLSession
 16 
 17     // Thread-safe email cache readable from nonisolated resolveActiveAccount()
 18     // without blocking the cooperative thread pool.
 19     private let _cachedEmail = OSAllocatedUnfairLock<AccountEmail?>(initialState: nil)
 20     private var lastKnownMetrics: [UsageMetric] = []
 21 
 22     // Fixed window durations (Codex policy mirrors Claude's windows)
 23     private static let sessionWindowMinutes = DurationMinutes(rawValue: 300)
 24     private static let weeklyWindowMinutes = DurationMinutes(rawValue: 10080)
 25 
 26     // Known-valid literal — force-unwrap is safe here
 27     private static let apiURL = URL(string: "https://chatgpt.com/backend-api/wham/usage")! // known-valid literal
 28 
 29     // Actor-isolated: safe without nonisolated(unsafe) since all access is on the actor
 30     private let isoFormatter: ISO8601DateFormatter = {
 31         let f = ISO8601DateFormatter()
 32         f.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
 33         return f
 34     }()
 35 
 36     public init(
 37         auth: CodexAuthProviding = CodexAuth(),
 38         logger: FileLogger = Loggers.codex,
 39         session: URLSession = .shared
 40     ) {
 41         self.auth = auth
 42         self.logger = logger
 43         self.session = session
 44     }
 45 
 46     // MARK: - UsageConnector
 47 
 48     nonisolated public func resolveActiveAccount() -> AccountEmail? {
 49         _cachedEmail.withLock { $0 }
 50     }
 51 
 52     /// Clears the cached email so the next `fetchUsages()` call resolves a fresh email
 53     /// from the API response. Called by the account monitor on account_id changes.
 54     public func invalidateEmailCache() {
 55         _cachedEmail.withLock { $0 = nil }
 56         logger.log(.info, "Codex email cache invalidated")
 57     }
 58 
 59     public func fetchUsages() async throws -> [VendorUsageEntry] {
 60         let credentials: CodexCredentials
 61         do {
 62             credentials = try await auth.load()
 63         } catch {
 64             logger.log(.error, "Codex credentials load failed: \(error)")
 65             return errorEntries(type: "token_error")
 66         }
 67 
 68         // Check token expiry before making any network call
 69         if let lastRefreshed = credentials.lastRefreshedAt,
 70            Date().timeIntervalSince(lastRefreshed) > CodexConstants.tokenLifetimeSeconds {
 71             logger.log(.warning, "Codex token expired (last refresh > 8 days ago) — run `codex login`")
 72             return errorEntries(type: "token_expired", credentials: credentials)
 73         }
 74 
 75         logger.log(.info, "Fetching Codex usages for accountId=\(credentials.accountId)")
 76 
 77         var request = URLRequest(url: Self.apiURL)
 78         request.setValue("Bearer \(credentials.accessToken)", forHTTPHeaderField: "Authorization")
 79         request.setValue(credentials.accountId.rawValue, forHTTPHeaderField: "ChatGPT-Account-Id")
 80         // Reproduces the User-Agent used in the OpenUsage analysis to avoid bot filtering
 81         request.setValue("OpenUsage", forHTTPHeaderField: "User-Agent")
 82         request.timeoutInterval = CodexConstants.requestTimeoutSeconds
 83 
 84         let data: Data
 85         let response: URLResponse
 86         do {
 87             (data, response) = try await session.data(for: request)
 88         } catch {
 89             logger.log(.error, "Codex API request failed: \(error)")
 90             return errorEntries(type: "api_error", credentials: credentials)
 91         }
 92 
 93         let httpResponse = response as? HTTPURLResponse
 94         let httpCode = httpResponse?.statusCode ?? -1
 95         logger.log(.info, "Codex API response: HTTP \(httpCode)")
 96 
 97         if httpCode == 401 {
 98             logger.log(.warning, "Codex API returned HTTP 401 — token expired or revoked")
 99             return errorEntries(type: "token_expired", credentials: credentials)
100         }
101 
102         if httpCode == 429 {
103             let body = String(data: data, encoding: .utf8) ?? "<non-UTF8 body, \(data.count) bytes>"
104             logger.log(.warning, "Codex API rate-limited (HTTP 429): \(body)")
105             return errorEntries(
106                 type: "http_429",
107                 credentials: credentials,
108                 isActive: true,
109                 preservedMetrics: lastKnownMetrics
110             )
111         }
112 
113         guard let http = httpResponse, http.statusCode == 200 else {
114             logger.log(.error, "Codex API returned HTTP \(httpCode)")
115             return errorEntries(type: "http_\(httpCode)", credentials: credentials)
116         }
117 
118         logger.log(.debug, "Codex API payload: \(Self.maskedPayload(data))")
119 
120         do {
121             let (metrics, emailFromResponse) = try parseAPIResponse(data, httpResponse: http)
122             guard let (account, source) = resolvePersistedAccount(
123                 responseEmail: emailFromResponse,
124                 credentials: credentials
125             ) else {
126                 logger.log(
127                     .warning,
128                     "Codex identity_unresolved during success response for accountId=\(credentials.accountId) — no usage entry written"
129                 )
130                 return []
131             }
132             lastKnownMetrics = metrics
133             logger.log(
134                 .info,
135                 "Codex fetched \(metrics.count) metric(s) for account=\(account) via \(source.rawValue)"
136             )
137             return [VendorUsageEntry(
138                 vendor: vendor,
139                 account: account,
140                 isActive: true,
141                 lastAcquiredOn: ISODate(date: Date()),
142                 lastError: nil,
143                 metrics: metrics
144             )]
145         } catch {
146             logger.log(.error, "Codex response parse failed: \(error)")
147             logger.log(.warning, "Codex failed payload dump: \(Self.maskedPayload(data))")
148             return errorEntries(type: "parse_error", credentials: credentials)
149         }
150     }
151 
152     // MARK: - Response parsing
153 
154     private func parseAPIResponse(_ data: Data, httpResponse: HTTPURLResponse) throws -> ([UsageMetric], AccountEmail?) {
155         let jsonObject = try JSONSerialization.jsonObject(with: data)
156         guard let json = jsonObject as? [String: Any] else {
157             throw CodexConnectorError.unexpectedAPIFormat(receivedKeys: [])
158         }
159 
160         let email = normalizedEmail(json["email"] as? String)
161         var metrics: [UsageMetric] = []
162 
163         // Primary and secondary rate-limit windows
164         let rateLimit = json["rate_limit"] as? [String: Any]
165         if let window = rateLimit?["primary_window"] as? [String: Any],
166            let w = extractWindow(from: window, fallbackDuration: Self.sessionWindowMinutes) {
167             metrics.append(.timeWindow(name: "Session (5h)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
168         }
169         if let window = rateLimit?["secondary_window"] as? [String: Any],
170            let w = extractWindow(from: window, fallbackDuration: Self.weeklyWindowMinutes) {
171             metrics.append(.timeWindow(name: "Weekly (7d)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
172         }
173 
174         // Code review rate limit (optional — absent on plans without code review)
175         let codeReviewRateLimit = json["code_review_rate_limit"] as? [String: Any]
176         if let window = codeReviewRateLimit?["primary_window"] as? [String: Any],
177            let w = extractWindow(from: window, fallbackDuration: Self.weeklyWindowMinutes) {
178             metrics.append(.timeWindow(name: "Code Review (7d)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
179         }
180 
181         // Per-model additional rate limits (e.g. Spark plan with per-model quotas)
182         let additionalRateLimits = json["additional_rate_limits"] as? [[String: Any]] ?? []
183         for limitEntry in additionalRateLimits {
184             guard let limitName = limitEntry["limit_name"] as? String else { continue }
185             let limitRateLimit = limitEntry["rate_limit"] as? [String: Any]
186             if let window = limitRateLimit?["primary_window"] as? [String: Any],
187                let w = extractWindow(from: window, fallbackDuration: Self.sessionWindowMinutes) {
188                 metrics.append(.timeWindow(name: "\(limitName) (5h)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
189             }
190             if let window = limitRateLimit?["secondary_window"] as? [String: Any],
191                let w = extractWindow(from: window, fallbackDuration: Self.weeklyWindowMinutes) {
192                 metrics.append(.timeWindow(name: "\(limitName) Weekly (7d)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
193             }
194         }
195 
196         // Credits: body-first, header as fallback
197         let credits = json["credits"] as? [String: Any]
198         let hasCredits = credits?["has_credits"] as? Bool ?? false
199         if hasCredits, let balance = credits?["balance"] as? Double, balance > 0 {
200             // "1000 - balance" expresses credits consumed; balance is the remaining allowance
201             metrics.append(.payAsYouGo(name: "Credits used", currentAmount: 1000.0 - balance, currency: "credits"))
202         } else if let headerValue = httpResponse.value(forHTTPHeaderField: "x-codex-credits-balance"),
203                   let balance = Double(headerValue), balance > 0 {
204             metrics.append(.payAsYouGo(name: "Credits used", currentAmount: 1000.0 - balance, currency: "credits"))
205         }
206 
207         if metrics.isEmpty, json["rate_limit"] == nil, additionalRateLimits.isEmpty {
208             logger.log(.warning, "No known usage window in Codex payload — top-level keys: \(Array(json.keys))")
209             throw CodexConnectorError.unexpectedAPIFormat(receivedKeys: Array(json.keys))
210         }
211 
212         return (metrics, email)
213     }
214 
215     // MARK: - Window extraction
216 
217     private struct WindowValues {
218         let percent: UsagePercent
219         let resetAt: ISODate?
220         let duration: DurationMinutes
221     }
222 
223     private func extractWindow(from window: [String: Any], fallbackDuration: DurationMinutes) -> WindowValues? {
224         guard let usedPercent = window["used_percent"] as? Double else {
225             logger.log(.debug, "Window block missing used_percent — skipped")
226             return nil
227         }
228         let resetAt: ISODate?
229         if let epochSecs = window["reset_at"] as? Double, epochSecs > 0 {
230             resetAt = ISODate(date: Date(timeIntervalSince1970: epochSecs))
231         } else {
232             resetAt = nil
233         }
234         let duration: DurationMinutes
235         if let secs = window["limit_window_seconds"] as? Double, secs > 0 {
236             duration = DurationMinutes(rawValue: Int(secs) / 60)
237         } else {
238             duration = fallbackDuration
239         }
240         return WindowValues(
241             percent: UsagePercent(rawValue: Int(usedPercent.rounded())),
242             resetAt: resetAt,
243             duration: duration
244         )
245     }
246 
247     // MARK: - Payload masking
248 
249     private static let sensitiveKeyPatterns = ["token", "key", "secret", "password", "email", "credential"]
250 
251     static func maskedPayload(_ data: Data) -> String {
252         guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
253             return "<non-JSON, \(data.count) bytes>"
254         }
255         let masked = maskSensitiveFields(json)
256         guard let out = try? JSONSerialization.data(withJSONObject: masked, options: [.sortedKeys]),
257               let str = String(data: out, encoding: .utf8) else {
258             return "<serialization failed>"
259         }
260         return str
261     }
262 
263     static func maskSensitiveFields(_ dict: [String: Any]) -> [String: Any] {
264         var result: [String: Any] = [:]
265         for (key, value) in dict {
266             let lower = key.lowercased()
267             if sensitiveKeyPatterns.contains(where: { lower.contains($0) }) {
268                 result[key] = "***"
269             } else if let nested = value as? [String: Any] {
270                 result[key] = maskSensitiveFields(nested)
271             } else if let array = value as? [[String: Any]] {
272                 result[key] = array.map { maskSensitiveFields($0) }
273             } else {
274                 result[key] = value
275             }
276         }
277         return result
278     }
279 
280     // MARK: - Helpers
281 
282     private func resolvePersistedAccount(
283         responseEmail: AccountEmail? = nil,
284         credentials: CodexCredentials? = nil
285     ) -> (AccountEmail, IdentitySource)? {
286         if let responseEmail {
287             _cachedEmail.withLock { $0 = responseEmail }
288             return (responseEmail, .responseBody)
289         }
290         if let accountEmail = credentials?.accountEmail {
291             _cachedEmail.withLock { $0 = accountEmail }
292             return (accountEmail, .credentials)
293         }
294         if let cached = _cachedEmail.withLock({ $0 }) {
295             return (cached, .cache)
296         }
297         return nil
298     }
299 
300     private func errorEntries(
301         type: String,
302         credentials: CodexCredentials? = nil,
303         isActive: Bool = false,
304         preservedMetrics: [UsageMetric] = []
305     ) -> [VendorUsageEntry] {
306         guard let (account, source) = resolvePersistedAccount(credentials: credentials) else {
307             let accountId = credentials?.accountId.rawValue ?? "<unavailable>"
308             logger.log(.warning, "Codex identity_unresolved during \(type) for accountId=\(accountId) — no usage entry written")
309             return []
310         }
311         logger.log(.debug, "Codex resolved account=\(account) via \(source.rawValue) for \(type)")
312         return [errorEntry(account: account, type: type, isActive: isActive, preservedMetrics: preservedMetrics)]
313     }
314 
315     private func normalizedEmail(_ rawValue: String?) -> AccountEmail? {
316         guard let rawValue else { return nil }
317         let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
318         guard !trimmed.isEmpty else { return nil }
319         return AccountEmail(rawValue: trimmed)
320     }
321 
322     private func errorEntry(account: AccountEmail, type: String, isActive: Bool = false, preservedMetrics: [UsageMetric] = []) -> VendorUsageEntry {
323         VendorUsageEntry(
324             vendor: vendor,
325             account: account,
326             isActive: isActive,
327             lastAcquiredOn: nil,
328             lastError: UsageError(timestamp: ISODate(date: Date()), type: type),
329             metrics: preservedMetrics
330         )
331     }
332 }
333 
334 public enum CodexConnectorError: Error, CustomStringConvertible {
335     case unexpectedAPIFormat(receivedKeys: [String])
336 
337     public var description: String {
338         switch self {
339         case let .unexpectedAPIFormat(keys):
340             "Codex API response does not match expected format — top-level keys: \(keys)"
341         }
342     }
343 }

