20         fileManager: FileManager = .default,
21         logger: FileLogger = Loggers.codex,
22         interval: Duration = CodexActiveAccountMonitor.defaultInterval,
23         onActiveAccountChanged: (@Sendable (AccountId) async -> Void)? = nil
24     ) {
25         self.codexHomePath = codexHomePath ?? ProcessInfo.processInfo.environment["CODEX_HOME"]
26         self.fileManager = fileManager
27         self.logger = logger
28         self.interval = interval
29         self.onActiveAccountChanged = onActiveAccountChanged
30     }
31 
32     public func start() {
33         guard monitorTask == nil else {
34             logger.log(.warning, "Codex active-account monitor already running")
35             return
36         }
37         logger.log(.info, "Starting Codex active-account monitor with interval \(interval)")
38         monitorTask = Task {
39             while !Task.isCancelled {
40                 await self.checkOnce()
41                 try? await Task.sleep(for: self.interval)
42                 guard !Task.isCancelled else { break }
43             }
44         }
45     }
46 
47     public func stop() {
48         monitorTask?.cancel()
49         monitorTask = nil
50         logger.log(.info, "Codex active-account monitor stopped")
51     }
52 
53     public func checkOnce() async {
54         guard let accountId = readAccountId() else {
55             // Transient state during `codex login` — auth.json may be absent briefly.
56             // Only trust positive signals; preserve the previous observed state otherwise.
57             logger.log(.debug, "Codex account ID unresolved — keeping previous state")
58             return
59         }
60 
61         let previous = lastObservedAccountId
62         lastObservedAccountId = accountId
63         // Skip the callback on the first resolution (startup) — only fire on genuine switches.
64         if let previous, previous != accountId {
65             logger.log(.info, "Codex account switched: \(accountId)")
66             await onActiveAccountChanged?(accountId)
67         }
68     }
69 
70     private func readAccountId() -> AccountId? {
71         let home = fileManager.homeDirectoryForCurrentUser.path
72 
73         var candidates: [String] = []
74         if let codexHome = codexHomePath {
75             candidates.append("\(codexHome)/auth.json")
76         }
77         candidates.append("\(home)/.config/codex/auth.json")
78         candidates.append("\(home)/.codex/auth.json")
79 
80         for path in candidates where fileManager.fileExists(atPath: path) {
81             guard let data = fileManager.contents(atPath: path) else { continue }
82             let jsonObject: Any
83             do {
84                 jsonObject = try JSONSerialization.jsonObject(with: data)
85             } catch {
86                 logger.log(.debug, "Failed to parse Codex auth at \(path): \(error)")
87                 continue
88             }
89             guard let json = jsonObject as? [String: Any],
90                   let tokens = json["tokens"] as? [String: Any],
91                   let accountId = tokens["account_id"] as? String,
92                   !accountId.isEmpty else { continue }
93             return AccountId(rawValue: accountId)
94         }
95         return nil
96     }
97 }

